local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdleEnemyMaker:LFightIdleBaseCtrl
local LFightIdleEnemyMaker = LxClass("LFightIdleEnemyMaker",LFightIdleBaseCtrl)
-----------------------------------------------------------------

local LFightIdleConst = LFightIdleConst
-----------------------------------------------------------------
function LFightIdleEnemyMaker:LFightIdleEnemyMaker()
	self._curWaveLifeCnt = 0

	self._bStartMake = false

	self._monNumPerUnit = 1
	self._boardUnit = 1
	self._enemyQualityList = {}

	self._boardEnemyMadeMap = {}

	self._cacheWaitList = {}
	self._cacheAreaLoadList = {}

	self._attrRefId = 0
end

function LFightIdleEnemyMaker:InitMaker(enemyList,boardNum,monWeightList,monQualityMaxList,monWeightAddList,attrRefId)
	enemyList = enemyList or {[LFightIdleConst.MON_QUALITY_NONE] = 1001}
	self:InitEnemyQuality(enemyList,monWeightList,monQualityMaxList,monWeightAddList)

	self._monNumPerUnit = boardNum.num
	self._boardUnit = boardNum.unit
	self._attrRefId = attrRefId or 0
	if self._boardUnit <= 0 then self._boardUnit = 1 end
end

function LFightIdleEnemyMaker:InitEnemyQuality(enemyList,monWeightList,monQualityMaxList,monWeightAddList)
	local qualityList = LFightIdleConst.MON_QUALITY_LIST
	local monQualityDataList = {}
	for k,v in ipairs(qualityList) do
		local monData = enemyList[v]
		if monData and #monData > 0 then
			local monQualityData = {
				quality = v,
				monList = monData,
				weight = monWeightList[v] or 0,
				limitNum = monQualityMaxList[v] or -1,
				addWeight = monWeightAddList[v] or 0,
				nowWeight = monWeightList[v] or 0}
			if v == LFightIdleConst.MON_QUALITY_NONE then
				--普通品质 ，其他品质都不刷新的时候，就是刷新普通品质
				--权重 -1 表示剩余概率
				monQualityData.weight = -1
				monQualityData.nowWeight = -1
			end
			table.insert(monQualityDataList,monQualityData)
		end
	end

	self._enemyQualityList = monQualityDataList
end
------------------------------------------------------------------
function LFightIdleEnemyMaker:ResetBoardEnemyMadeMap()
	self._boardEnemyMadeMap = {}
end

