function LFightIdleEnemyMaker:MakeEnemyInBoards(boardNameList, totalCount)
	local mgr = self._manager
	local objCtrl = mgr:GetObjCtrl()
	local areaCtrl = mgr:GetAreaCtrl()

	local enemyNowList = self._enemyQualityList

	local objLen = 0
	local objRootTrans = mgr:GetObjectRootTrans()

	local cacheWaitList = self._cacheWaitList

	local attrRefId = self._attrRefId

	local boardLen = #boardNameList
	if boardLen == 0 then return end

	local boardInfoDataMap = {}
	local boardMaxCount = 0
	for k,boardKey in ipairs(boardNameList) do
		local boardRef = mgr:GetBoardRef(boardKey)
		local boardWidth = boardRef.width or 2
		local count = Mathf.Round(boardWidth * self._monNumPerUnit / self._boardUnit)
		if boardMaxCount < count then
			boardMaxCount = count
		end
		boardInfoDataMap[boardKey] = { max=count, cur=0, isFull=false, ref=boardRef, key=boardKey, indexPaths={}, limitQuality={}, enemyNowData={}}
	end


	local validSeqList = {}
	local curWav = 0
	local bIgnoreLimit = false

	for k=1, totalCount do
		if #validSeqList == 0 then
			curWav = curWav + 1
			if bIgnoreLimit then
				validSeqList = LFightIdleConst.GenerateSeqList(boardLen)
			else
				for m,v in ipairs(boardNameList) do
					if(not boardInfoDataMap[v].isFull) then
						table.insert(validSeqList, m)
					end
				end
				bIgnoreLimit = curWav >= boardMaxCount
				if #validSeqList == 0 then
					validSeqList = LFightIdleConst.GenerateSeqList(boardLen)
				end
			end
		end

		--随机一个地板
		local validIndex = LFightIdleConst.RandInteger(#validSeqList)
		local boardKey = boardNameList[table.remove(validSeqList,validIndex)]

		local boardInfoData = boardInfoDataMap[boardKey]
		local curCount = boardInfoData.cur + 1
		boardInfoData.cur = curCount
		if curCount >= boardInfoData.max then
			boardInfoData.isFull = true
		end

		--随机一个路径
		local boardRef = boardInfoData.ref
		local paths = boardRef.paths
		local indexPaths = boardInfoData.indexPaths
		if(#indexPaths == 0) then
			indexPaths = LFightIdleConst.GenerateSeqList(#boardRef.paths)
			boardInfoData.indexPaths = indexPaths
		end


		local limitQuality = boardInfoData.limitQuality
		local enemyNowData = boardInfoData.enemyNowData

		--随机一个品质野怪
		--根据权重随机一个品质的怪物列表，再从怪物列表中随机一个，品质怪物数量+1，当达到限制时候，当前权重设置0
		local rand = math.random()
		local qualityData = nil

		for k,v in ipairs(enemyNowList) do
			if not limitQuality[v.quality] then
				--负1 的概率表示 最后会随机到它
				if v.nowWeight < 0 or rand < v.nowWeight  then
					qualityData = v
					break
				end
				rand = rand - v.nowWeight
			end
		end
		if not qualityData then qualityData = enemyNowList[#enemyNowList] end

		local quality = qualityData.quality
		local monList = qualityData.monList
		local limitNum = qualityData.limitNum

		local nowQualityMonNum = (enemyNowData[quality] or 0) + 1
		enemyNowData[quality] = nowQualityMonNum

		if limitNum > 0 and nowQualityMonNum >= limitNum then
			limitQuality[quality] = true
		end

		--没刷新的概率递增
		--刷新之后权重回复默认
		for k,v in ipairs(enemyNowList) do
			if v == qualityData then
				v.nowWeight = v.weight
			else
				v.nowWeight = v.nowWeight + v.addWeight
			end
		end

		local refId = monList[LFightIdleConst.RandInteger(#monList)]

		---@type LFightIdleObject
		local obj = nil
		if refId then
			obj = objCtrl:MakeClientObject(objRootTrans,{refId=refId,attrRefId=attrRefId,quality=quality})
		end
		if obj then
			obj:SetQuality(quality)
			obj:SetAreaIndex(areaCtrl:GetAreaIndexByAreaId(boardRef.areaId))
			obj:SetBoardRefId(boardKey)
			local indexPathIdx = LFightIdleConst.RandInteger(#indexPaths)
			local pathIndex = table.remove(indexPaths, indexPathIdx)
			obj:SetPathIndex(pathIndex)
			local minPos,maxPos,nowPos = LFightIdleConst.RandPos(paths[pathIndex],curCount)
			obj:SetPathData(minPos,maxPos)
			obj:SetBirthPos(nowPos:Clone())
			obj:SetPosition(nowPos:Clone())
			objCtrl:AddObject(obj)
			objLen = objLen + 1

			--按照距离来加载
			table.insert(cacheWaitList, obj)
		end
	end

	self._curWaveLifeCnt = self._curWaveLifeCnt + objLen
end
