---@param areaData LFightIdleArea
function LFightIdleEnemyMaker:MakeNextAreaEnemy(areaData,areaIndex)
	local boardNameList = areaData:GetBoardNameList()
	local mgr = self._manager
	local objCtrl = mgr:GetObjCtrl()
	local areaCtrl = mgr:GetAreaCtrl()

	local areaSize = areaCtrl:GetAreaSize()
	local moveType = areaCtrl:GetMoveType()

	local enemyNowList = self._enemyQualityList
	local enemyNowData = {}
	local objLen = 0
	local objRootTrans = mgr:GetObjectRootTrans()

	local bHorizontal = moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL

	local cacheAreaLoadList = self._cacheAreaLoadList
	local boardEnemyMadeMap = self._boardEnemyMadeMap
	local limitQuality = {}
	local attrRefId = self._attrRefId
	for k,boardKey in ipairs(boardNameList) do
		if not boardEnemyMadeMap[boardKey] then
			boardEnemyMadeMap[boardKey] = true

			local boardRef = mgr:GetBoardRef(boardKey)

			---映射的地方刷怪 其实 还是要移动回到开始位置的
			if not string.isempty(boardRef.shadow) then
				boardEnemyMadeMap[boardRef.shadow] = true
			end

			local paths = boardRef.paths
			local boardWidth = boardRef.width or 2

			local count = Mathf.Round(boardWidth * self._monNumPerUnit / self._boardUnit)

			local copyPathIndex = LFightIdleConst.GenerateSeqList(#paths)
			for m=1,count do
				if #copyPathIndex == 0 then
					copyPathIndex = LFightIdleConst.GenerateSeqList(#paths)
				end

				--根据权重随机一个品质的怪物列表，再从怪物列表中随机一个，品质怪物数量+1，当达到限制时候，当前权重设置0
				local rand = math.random()
				local qualityData = nil

				for k,v in ipairs(enemyNowList) do
					if not limitQuality[v.quality] then
						--负1 的概率表示 最后会随机到它
						if v.nowWeight < 0 or rand < v.nowWeight  then
							qualityData = v
							break
						end
						rand = rand - v.nowWeight
					end
				end
				if not qualityData then qualityData = enemyNowList[#enemyNowList] end

				local quality = qualityData.quality
				local monList = qualityData.monList
				local limitNum = qualityData.limitNum

				local nowQualityMonNum = (enemyNowData[quality] or 0) + 1
				enemyNowData[quality] = nowQualityMonNum

				if limitNum > 0 and nowQualityMonNum >= limitNum then
					limitQuality[quality] = true
				end

				--没刷新的概率递增
				--刷新之后权重回复默认
				for k,v in ipairs(enemyNowList) do
					if v == qualityData then
						v.nowWeight = v.weight
					else
						v.nowWeight = v.nowWeight + v.addWeight
					end
				end

				local refId = monList[LFightIdleConst.RandInteger(#monList)]

				---@type LFightIdleObject
				local obj = nil
				if refId then
					obj = objCtrl:MakeClientObject(objRootTrans,{refId=refId,attrRefId=attrRefId,quality=quality})
				end
				if obj then
					obj:SetQuality(quality)
					obj:SetAreaIndex(areaIndex)
					obj:SetBoardRefId(boardKey)
					local pathIndex = LFightIdleConst.RandInteger(#copyPathIndex)
					pathIndex = table.remove(copyPathIndex,pathIndex)
					obj:SetPathIndex(pathIndex)
					local minPos,maxPos,nowPos = LFightIdleConst.RandPos(paths[pathIndex],m)
					obj:SetPathData(minPos,maxPos)
					obj:SetBirthPos(nowPos:Clone())
					obj:SetPosition(nowPos:Clone())
					objCtrl:AddObject(obj)
					objLen = objLen + 1
					--obj:StartLoadDp()

					--按照距离来加载
					local pos = obj:GetBirthPos()
					local cacheIndex
					if bHorizontal then
						cacheIndex = pos.x
					else
						cacheIndex = pos.y
					end
					if cacheIndex < 0 then cacheIndex = 0 end
					cacheIndex = math.ceil(cacheIndex / areaSize)
					local objList = cacheAreaLoadList[cacheIndex] or {}
					table.insert(objList,obj)
					cacheAreaLoadList[cacheIndex] = objList
				end
			end
		end
	end
	self._curWaveLifeCnt = self._curWaveLifeCnt + objLen
end

-----------------------------------------------------------------
function LFightIdleEnemyMaker:OnEnemyDead(obj)
	self._curWaveLifeCnt = self._curWaveLifeCnt - 1
end

function LFightIdleEnemyMaker:GetLifeCnt()
	return self._curWaveLifeCnt
end
-----------------------------------------------------------------

function LFightIdleEnemyMaker:OnRun(time)
	local cacheWaitList = self._cacheWaitList
	local len = #cacheWaitList
	if len > 0 then
		local cacheLimit = 1
		cacheLimit = math.min(cacheLimit,len)
		for k=1,cacheLimit do
			local obj = table.remove(cacheWaitList,1)
			if obj and not obj:IsDestroy() then
				obj:StartLoadDp()
			end
		end
	end
end

function LFightIdleEnemyMaker:CheckCacheLoadArea(lastArea)
	local cacheWaitList = self._cacheWaitList
	for k,v in pairs(self._cacheAreaLoadList) do
		if k <= lastArea then
			for m,n in ipairs(v) do
				table.insert(cacheWaitList,n)
			end
			self._cacheAreaLoadList[k] = nil
		end
	end
end

-----------------------------------------------------------------
function LFightIdleEnemyMaker:Destroy()
	table.removeall(self)
end

return LFightIdleEnemyMaker